def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5)+1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def complex_factorial(n):
        f = 1
        for i in range(1, n+1):
            f *= i
        return f
    def collatz_steps(n):
        steps = 0
        visited = set()
        while n != 1 and n not in visited and steps < 500:
            visited.add(n)
            if n % 2 == 0:
                n = n // 2
            else:
                n = 3 * n + 1
            steps += 1
        return steps
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else -1000
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                term = np.exp(-a*ratio*7) * (18 / (a+2)) * (np.cos(cap*a) + 1.5)
                score += term
            for b in range(1, int(cap//3)+1):
                if cap % b == 0 and is_prime(b):
                    score += (b**0.5) * 1.5
            if int(cap) % 7 == 0:
                score *= 1.15
            if int(cap) % 13 == 0:
                score += 17
        elif 0.1 <= ratio < 0.35:
            base = np.sin(ratio*np.pi*3)*20 + np.log1p(cap)*2
            series_sum = 0
            for c in range(1, 7):
                series_sum += ((-1)**c) * (ratio**c) / (c**1.5)
            score += base + series_sum * 12
            divisible = False
            for d in [5,8,10]:
                if int(cap) % d == 0:
                    score += d * 0.8
                    divisible = True
            if divisible:
                score *= 1.09
        elif 0.35 <= ratio <= 0.65:
            sine_comp = np.sin(ratio*np.pi*7)*15
            fact_sum = 0
            for e in range(1,9):
                fct = complex_factorial(e)
                fact_sum += ((-1)**(e+1))*(ratio**e)/fct
            score += sine_comp + fact_sum*11
            prime_sum = 0
            for g in range(3, int(min(15, cap))):
                if is_prime(g) and cap % g == 0 and g % 3 != 0:
                    prime_sum += np.sqrt(g)*3
            score += prime_sum
            collatz_val = collatz_steps(int(cap))
            score += collatz_val * 0.5
        elif 0.65 < ratio <= 0.9:
            logistic = 40 / (1 + np.exp(-30*(ratio - 0.75)))
            score += logistic
            for h in range(2, 12):
                if is_prime(h):
                    score += h * 1.1
            if ratio > 0.85:
                score += (1 - ratio) * 85
            if int(cap) % 4 == 0:
                score *= 1.13
            if int(cap) % 6 == 0 and ratio < 0.88:
                score *= 1.08
        elif 0.9 < ratio <= 1.2:
            penalty = 0
            chunk = max(2, int(cap//4))
            for i in range(1, chunk+1):
                if cap % i == 0:
                    penalty += i ** 1.5
            fract = ratio - int(ratio)
            for j in range(1, 10):
                mod_val = (fract * j * 990) % 11
                penalty += (mod_val / 11) * 7
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-60)
            if int(cap) % 17 == 0:
                score *= 0.85
            if int(cap) % 19 == 0:
                score += 22
            if ratio > 1.1:
                score += (1.2 - ratio)*40
        elif 1.2 < ratio < 2.0:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 2 == 0:
                        complex_sum += np.log1p(k)*4
                    else:
                        complex_sum += np.sqrt(k)*3
            fract_part = ratio - int(ratio)
            for m in range(1, 12):
                complex_sum += np.cos(fract_part * m * np.pi)*3
            score += complex_sum
            score += (ratio - 1.5)*30
            if ratio > 1.8:
                for n in range(1, int(cap//2)+1):
                    if n % 5 == 0:
                        score += np.sin(n)*5
            if int(cap) % 9 == 0:
                score *= 0.77
        else:
            ultra_sum = 0
            for p in range(1, int(min(25, cap))):
                if cap % p == 0:
                    if p % 3 == 0:
                        ultra_sum += np.sqrt(p)*4
                    else:
                        ultra_sum += np.log1p(p)*5
            fract_full = ratio - int(ratio)
            for q in range(1, 15):
                ultra_sum += np.sin(fract_full * q * np.pi) * 3
            score += ultra_sum
            score += (ratio - 3)*80
            if ratio > 5:
                for r in range(1, int(cap//4)+1):
                    if r % 11 == 0:
                        score += np.cos(r)*6
            if int(cap) % 8 == 0:
                score *= 0.7
            if int(cap) % 16 == 0:
                score *= 0.65
        if int(cap) % 7 == 0 and ratio < 1.5:
            score *= 1.1
        if int(cap) % 3 == 0 and ratio > 0.3:
            score *= 0.8
        if ratio > 4.5 and int(cap) % 20 == 0:
            score += 25
        if int(cap) % 2 == 0 and ratio > 2:
            score *= 1.05
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 400)
    return priorities
